// App.jsx (React)
import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import axios from 'axios';

// इम्पोर्ट्स (या फाईल्स तुमच्या pages फोल्डरमध्ये असायला हव्यात)
import Navbar from './components/Navbar';
import Marketplace from './pages/Marketplace';

function App() {
  const [jobs, setJobs] = useState([]);

  useEffect(() => {
    // बॅकएंडवरून जॉब्स आणणे (जेव्हा डॅशबोर्डवर असाल)
    axios.get('http://localhost:5000/api/jobs')
      .then(res => setJobs(res.data))
      .catch(err => console.error(err));
  }, []);

  return (
    <Router>
      <div className="min-h-screen bg-gray-100">
        {/* १. नेव्हबार नेहमी वर दिसेल */}
        <Navbar />

        <Routes>
          {/* २. मुख्य होम पेज (येथे आपण डॅशबोर्डचा जुना कोड टाकला आहे) */}
          <Route path="/" element={
            <div className="flex">
              {/* Sidebar */}
              <div className="w-64 bg-slate-900 text-white p-6 shadow-xl min-h-screen">
                <h2 className="text-2xl font-bold text-blue-400 mb-10">FreelanceHub</h2>
                <nav className="space-y-4">
                  <a href="#" className="block p-3 bg-blue-600 rounded">Dashboard</a>
                  <a href="#" className="block p-3 hover:bg-slate-700 transition">Find Jobs</a>
                </nav>
              </div>

              {/* Main Content */}
              <div className="flex-1 p-10">
                <header className="flex justify-between items-center mb-10">
                  <h1 className="text-3xl font-bold text-gray-800">Available Projects</h1>
                  <button className="bg-green-500 text-white px-6 py-2 rounded-full font-semibold shadow-lg">Post a Job</button>
                </header>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {jobs.length > 0 ? jobs.map(job => (
                    <div key={job._id} className="bg-white p-6 rounded-xl shadow-md border-t-4 border-blue-500">
                      <h3 className="text-xl font-bold text-gray-800">{job.title}</h3>
                      <p className="text-blue-600 font-semibold mt-2">{job.budget}</p>
                      <button className="w-full mt-6 bg-slate-800 text-white py-2 rounded-lg">Bid Now</button>
                    </div>
                  )) : <p>कोणतेही जॉब्स उपलब्ध नाहीत (Backend चालू करा).</p>}
                </div>
              </div>
            </div>
          } />

          {/* ३. मार्केटप्लेस रूट (येथे कॅटेगरी सिस्टीम काम करेल) */}
          <Route path="/marketplace" element={<Marketplace />} />
          
          {/* ४. लॉगिन रूट (गरज असल्यास) */}
          <Route path="/login" element={<div className="p-20 text-center">Login Page लवकरच येत आहे...</div>} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
